1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: Cell[] = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
10	
11	export function nextGeneration(cells: Cell[]): Cell[] {
12	  const aliveKeys = new Set(cells.map(cellKey));
13	
14	  const neighborCounts = new Map<string, { cell: Cell; count: number }>();
15	  for (const [x, y] of cells) {
16	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
17	      const neighbor: Cell = [x + dx, y + dy];
18	      const k = cellKey(neighbor);
19	      const entry = neighborCounts.get(k);
20	      if (entry) entry.count++;
21	      else neighborCounts.set(k, { cell: neighbor, count: 1 });
22	    }
23	  }
24	
25	  const survives = (k: string, count: number): boolean =>
26	    count === 3 || (count === 2 && aliveKeys.has(k));
27	
28	  return [...neighborCounts]
29	    .filter(([k, { count }]) => survives(k, count))
30	    .map(([, { cell }]) => cell);
31	}
