1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	type Cell = [number, number];
5	const sortCells = (cells: Cell[]): Cell[] =>
6	  [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
7	
8	describe("Game of Life - Next Generation", () => {
9	  it("should return empty array when given empty array", () => {
10	    expect(nextGeneration([])).toEqual([]);
11	  });
12	  it("should kill a single live cell (underpopulation)", () => {
13	    expect(nextGeneration([[0, 0]])).toEqual([]);
14	  });
15	  it("should kill two adjacent live cells (underpopulation)", () => {
16	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
17	  });
18	  it("should keep a block (2x2) stable as a still life", () => {
19	    const block: Cell[] = [[0, 0], [1, 0], [0, 1], [1, 1]];
20	    expect(sortCells(nextGeneration(block))).toEqual(sortCells(block));
21	  });
22	  it("should oscillate a vertical blinker to horizontal", () => {
23	    const vertical: Cell[] = [[0, 0], [0, 1], [0, 2]];
24	    const horizontal: Cell[] = [[-1, 1], [0, 1], [1, 1]];
25	    expect(sortCells(nextGeneration(vertical))).toEqual(sortCells(horizontal));
26	  });
27	  it("should birth a dead cell with exactly 3 live neighbors (reproduction)", () => {
28	    const input: Cell[] = [[0, 2], [1, 2], [0, 1]];
29	    const expected: Cell[] = [[0, 2], [1, 2], [0, 1], [1, 1]];
30	    expect(sortCells(nextGeneration(input))).toEqual(sortCells(expected));
31	  });
